function uuidv4() {
  if (globalThis.crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const root = $input.first().json || {};
let body = root.body || root;
// Replay payloads may carry the full webhook envelope ({headers,query,body}); unwrap it.
if (body && typeof body === 'object' && body.body && typeof body.body === 'object' && (body.headers || body.query || body.webhookUrl)) body = body.body;
const replay = !!root.replay;
const response_required = !!root.body && !replay;
const tenant_id = body.tenant_id || root.tenant_id || null;
const dayBucket = new Date().toISOString().slice(0, 10);
const event_id = body.event_id || body.run_id || ('compliance-' + (response_required ? 'manual-' : '') + (tenant_id || 'all') + '-' + dayBucket);
const retentionRaw = Number(body.retention_days);
const retentionDefault = Number($env.COMPLIANCE_RETENTION_DAYS) > 0 ? Number($env.COMPLIANCE_RETENTION_DAYS) : 365;
const retention_days = Number.isFinite(retentionRaw) && retentionRaw > 0 ? Math.min(Math.round(retentionRaw), 3650) : retentionDefault;
const correlation_id = replay && root.correlation_id ? root.correlation_id : uuidv4();

return [{ json: {
  tenant_id,
  event_id,
  retention_days,
  idem_key: 'compliance:' + event_id,
  replay,
  response_required,
  correlation_id,
  execution_id: String($execution.id),
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, '')
} }];

const p = $('Normalize Run').first().json;
const H = {
  apikey: $env.SUPABASE_SERVICE_KEY,
  Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
  accept: 'application/json',
  'content-type': 'application/json'
};
const prefer = Object.assign({}, H, { Prefer: 'return=representation' });
const helpers = this.helpers;
function enc(value) {
  return encodeURIComponent(String(value));
}
async function get(path) {
  return await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path, headers: H, json: true });
}
// Paginated fetch: PostgREST caps responses (max-rows); Range pages prevent silent row drop.
async function getAll(path, pageSize = 1000) {
  const out = [];
  for (let from = 0; ; from += pageSize) {
    const page = await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path, headers: Object.assign({}, H, { Range: from + '-' + (from + pageSize - 1), 'Range-Unit': 'items' }), json: true });
    if (!Array.isArray(page) || page.length === 0) break;
    out.push(...page);
    if (page.length < pageSize) break;
  }
  return out;
}
// Exact server-side count without fetching rows (Content-Range: */N).
async function countWhere(path) {
  const res = await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path + '&limit=1', headers: Object.assign({}, H, { Prefer: 'count=exact' }), json: true, returnFullResponse: true });
  const cr = (res.headers && (res.headers['content-range'] || res.headers['Content-Range'])) || '';
  const total = Number(String(cr).split('/')[1]);
  return Number.isFinite(total) ? total : null;
}
async function post(path, body) {
  return await helpers.httpRequest({ method: 'POST', url: p.supabase_url + path, headers: prefer, body, json: true });
}

const tenantFilter = p.tenant_id ? '&tenant_id=eq.' + enc(p.tenant_id) : '';
const audit = await get('/rest/v1/audit_log?select=tenant_id,correlation_id,service,step,status,payload,created_at' + tenantFilter + '&order=created_at.desc&limit=200');
const dlq = await get('/rest/v1/dead_letter_queue?select=id,tenant_id,correlation_id,workflow,error_class,status,attempts,created_at' + tenantFilter + '&order=created_at.desc&limit=100');
const dsar = await get('/rest/v1/dsar_requests?select=id,tenant_id,email,type,status,created_at' + tenantFilter + '&order=created_at.desc&limit=100');
const approvals = await get('/rest/v1/v_pending_approvals?select=tenant_id,tenant_name,correlation_id,service,step,created_at' + tenantFilter + '&limit=100');
const since = new Date(Date.now() - p.retention_days * 24 * 60 * 60 * 1000).toISOString();
// Exact count of rows past retention (server-side); sampling the newest 200 rows
// would systematically report 0 candidates.
const retentionCount = await countWhere('/rest/v1/audit_log?select=id' + tenantFilter + '&created_at=lt.' + enc(since));

const byStatus = {};
for (const row of audit || []) byStatus[row.status] = (byStatus[row.status] || 0) + 1;
const byService = {};
for (const row of audit || []) byService[row.service] = (byService[row.service] || 0) + 1;
const dlqByStatus = {};
for (const row of dlq || []) dlqByStatus[row.status] = (dlqByStatus[row.status] || 0) + 1;
const dsarByStatus = {};
for (const row of dsar || []) dsarByStatus[row.status] = (dsarByStatus[row.status] || 0) + 1;

const report = {
  tenant_scope: p.tenant_id || 'all',
  retention_days: p.retention_days,
  generated_at: new Date().toISOString(),
  audit: {
    row_count: (audit || []).length,
    by_status: byStatus,
    by_service: byService
  },
  dlq: {
    row_count: (dlq || []).length,
    by_status: dlqByStatus,
    // Data minimization: ids only. Raw error text/payloads stay out of this
    // anon-readable table; the operator drills in via the DLQ UI.
    manual_or_open_count: (dlq || []).filter((row) => ['open', 'manual'].includes(row.status)).length,
    manual_or_open_ids: (dlq || []).filter((row) => ['open', 'manual'].includes(row.status)).slice(0, 20).map((row) => row.id)
  },
  dsar: {
    row_count: (dsar || []).length,
    by_status: dsarByStatus
  },
  approvals: {
    pending_count: (approvals || []).length,
    // Data minimization: service/step counts only; payload amounts + tenant names
    // are readable via the RLS-scoped v_pending_approvals view instead.
    pending_by_service: (approvals || []).reduce((acc, row) => { acc[row.service] = (acc[row.service] || 0) + 1; return acc; }, {})
  },
  retention: {
    candidate_count: retentionCount != null ? retentionCount : 0,
    count_exact: retentionCount != null,
    cutoff: since,
    mode: 'report-only'
  }
};

const md = [
  '# FlowOps compliance export',
  '',
  '- Tenant scope: ' + report.tenant_scope,
  '- Generated at: ' + report.generated_at,
  '- Audit rows sampled: ' + report.audit.row_count,
  '- DLQ rows sampled: ' + report.dlq.row_count,
  '- Pending approvals: ' + report.approvals.pending_count,
  '- DSAR rows sampled: ' + report.dsar.row_count,
  '- Retention candidates: ' + report.retention.candidate_count + ' older than ' + p.retention_days + ' days',
  '',
  '## Audit by service',
  JSON.stringify(report.audit.by_service, null, 2),
  '',
  '## DLQ by status',
  JSON.stringify(report.dlq.by_status, null, 2)
].join('\n');

const rows = await post('/rest/v1/compliance_exports', [{
  correlation_id: p.correlation_id,
  tenant_id: p.tenant_id || null,
  status: 'completed',
  report_md: md,
  report
}]);
const exportRow = Array.isArray(rows) ? rows[0] : rows;

let telegram_delivered = false;
let notice = null;
if (p.telegram_token && p.telegram_chat) {
  const text = ['FlowOps compliance export', 'Scope: ' + report.tenant_scope, 'Audit rows: ' + report.audit.row_count, 'DLQ open/manual: ' + report.dlq.manual_or_open_count, 'Correlation: ' + p.correlation_id].join('\n');
  try {
    await this.helpers.httpRequest({ method: 'POST', url: 'https://api.telegram.org/bot' + p.telegram_token + '/sendMessage', body: { chat_id: p.telegram_chat, text }, json: true });
    telegram_delivered = true;
  } catch (e) {
    notice = 'telegram failed: ' + (e && e.message ? e.message : String(e));
  }
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}

return [{ json: { export_id: exportRow && exportRow.id, tenant_id: p.tenant_id || null, correlation_id: p.correlation_id, report, report_md: md, telegram_delivered, notice } }];

const r = $('Build Compliance Export').first().json;
return [{ json: {
  tenant_id: r.tenant_id,
  correlation_id: r.correlation_id,
  service: 'compliance',
  step: 'export',
  status: 'success',
  payload: { export_id: r.export_id, tenant_scope: r.report.tenant_scope, audit_rows: r.report.audit.row_count, dlq_rows: r.report.dlq.row_count, pending_approvals: r.report.approvals.pending_count, retention_candidates: r.report.retention.candidate_count, telegram_delivered: r.telegram_delivered, notice: r.notice }
} }];
